sql.where:
invokeRecord.user_id = #{userId}

  and invokeRecord.status = #{status}



      and invokeRecord.start_time >= #{startTime}




      and invokeRecord.end_time <= #{endTime}



  and app.app_name like concat('%', #{appName}, '%')


  and exists (
    select 1
    from invoke_record_detail detail_keyword
    where detail_keyword.invoke_record_id = invokeRecord.id
      and detail_keyword.user_input like concat('%', #{userInputKeyword}, '%')
  )

mapper.select:

from (
  select invokeRecord.* from invoke_record invokeRecord

  order by invokeRecord.id desc
  limit #{start},#{pageSize}
) invokeRecord

order by invokeRecord.id desc
